    /// <summary>
    /// Extensible enum for known Event values.
    /// </summary>
    [JsonConverter(typeof(Event.EventJsonConverter))]
    public readonly struct Event : IEquatable<Event>
    {
        private readonly string _value;

        /// <summary>
        /// Initializes a new instance of the <see cref="Event"/> struct.
        /// </summary>
        /// <param name="value">The string value.</param>
        public Event(string value) => this._value = value ?? throw new ArgumentNullException(nameof(value));

        /// <summary>msg_received</summary>
        public static Event MsgReceived { get; } = new("msg_received");

        /// <summary>msg_sent</summary>
        public static Event MsgSent { get; } = new("msg_sent");

        /// <summary>Converts a string to <see cref="Event"/>.</summary>
        public static implicit operator Event(string value) => new(value);

        /// <summary>Converts a <see cref="Event"/> to its string representation.</summary>
        public static implicit operator string(Event value) => value.ToString();

        /// <inheritdoc/>
        public override string ToString() => this._value;

        /// <inheritdoc/>
        public bool Equals(Event other) => string.Equals(this._value, other._value, StringComparison.OrdinalIgnoreCase);

        /// <inheritdoc/>
        public override bool Equals(object obj) => obj is Event other ? this.Equals(other) : obj is string text && string.Equals(this._value, text, StringComparison.OrdinalIgnoreCase);

        /// <inheritdoc/>
        public override int GetHashCode() => this._value?.GetHashCode(StringComparison.OrdinalIgnoreCase) ?? 0;

        /// <summary>Equality operator.</summary>
        public static bool operator ==(Event left, Event right) => left.Equals(right);

        /// <summary>Inequality operator.</summary>
        public static bool operator !=(Event left, Event right) => !left.Equals(right);

        internal sealed class EventJsonConverter : JsonConverter<Event>
        {
            public EventJsonConverter() { }
            public override Event Read(ref Utf8JsonReader reader, Type typeToConvert, JsonSerializerOptions options) => reader.TokenType == JsonTokenType.String ? new(reader.GetString()) : throw new JsonException($"Expected string for Event, got '{reader.TokenType}'.");
            public override void Write(Utf8JsonWriter writer, Event value, JsonSerializerOptions options) => writer.WriteStringValue(value.ToString());
        }
    }

